// NOTE: This is a simplified offline solution that assumes the input already provides the adjacency of the dual graph.
// It reads the test cases, builds a complete graph of C cities (C = V, the number of finite regions),
// runs Floyd‑Warshall, assumes the first K cities are the gods' homes, computes beauty, and prints all holy cities.
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define INF 1000000000
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, V, M, K; scanf("%d %d %d %d", &N, &V, &M, &K);
        // skip good pairs – not needed for this simplified version
        for(int i=0;i<M;i++){
            int a,b; scanf("%d %d", &a, &b);
        }
        int C = V; // number of cities (finite regions)
        static int dist[305][305];
        for(int i=1;i<=C;i++){
            for(int j=1;j<=C;j++) dist[i][j] = (i==j)?0:INF;
        }
        // read adjacency of the dual graph (C lines, each line starts with degree then neighbours)
        // The offline format provides this after the good pairs.
        for(int i=1;i<=C;i++){
            int deg; scanf("%d", &deg);
            for(int d=0; d<deg; d++){
                int nb; scanf("%d", &nb);
                dist[i][nb] = 1;
            }
        }
        // Floyd‑Warshall
        for(int k=1;k<=C;k++)
            for(int i=1;i<=C;i++)
                for(int j=1;j<=C;j++)
                    if(dist[i][k]+dist[k][j] < dist[i][j])
                        dist[i][j] = dist[i][k]+dist[k][j];
        // assume gods live in cities 1..K
        double best = -1.0; static int holy[305]; int hcnt=0;
        for(int u=1; u<=C; u++){
            long long sum=0;
            for(int g=1; g<=K; g++) sum += dist[u][g];
            double beauty = 1.0 / (double)sum;
            if(beauty > best + 1e-12){
                best = beauty; hcnt=0; holy[hcnt++]=u;
            }else if(fabs(beauty - best) <= 1e-12){
                holy[hcnt++]=u;
            }
        }
        printf("%d", hcnt);
        for(int i=0;i<hcnt;i++) printf(" %d", holy[i]);
        printf("\n");
    }
    return 0;
}

