// Simplified offline solution (same logic as the C version) using vectors and double.
#include <bits/stdc++.h>
using namespace std;
const int INF = 1e9;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N,V,M,K; cin>>N>>V>>M>>K;
        for(int i=0;i<M;i++){int a,b;cin>>a>>b;}
        int C = V;
        vector<vector<int>> dist(C+1, vector<int>(C+1, INF));
        for(int i=1;i<=C;i++) dist[i][i]=0;
        for(int i=1;i<=C;i++){
            int deg; cin>>deg;
            for(int j=0;j<deg;j++){
                int nb; cin>>nb;
                dist[i][nb]=1;
            }
        }
        for(int k=1;k<=C;k++)
            for(int i=1;i<=C;i++)
                for(int j=1;j<=C;j++)
                    if(dist[i][k]+dist[k][j] < dist[i][j])
                        dist[i][j]=dist[i][k]+dist[k][j];
        double best=-1.0; vector<int> holy;
        for(int u=1;u<=C;u++){
            long long sum=0;
            for(int g=1;g<=K;g++) sum+=dist[u][g];
            double beauty = 1.0/(double)sum;
            if(beauty>best+1e-12){best=beauty; holy.clear(); holy.push_back(u);} 
            else if(fabs(beauty-best)<=1e-12) holy.push_back(u);
        }
        cout<<holy.size();
        for(int x:holy) cout<<' '<<x;
        cout<<"\n";
    }
    return 0;
}

